const input = $input.first().json;
const body = input.body && typeof input.body === 'object' ? input.body : input;

function asString(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function asBool(value) {
  return value === true || value === 'true' || value === 1 || value === '1';
}

let maxResults = parseInt(body.max_results ?? 5, 10);
if (!Number.isFinite(maxResults)) maxResults = 5;
maxResults = Math.max(1, Math.min(maxResults, 10));

const parts = [];
const query = asString(body.query);
const fromAddress = asString(body.from_address);
const subject = asString(body.subject);

if (query) parts.push(query);
if (asBool(body.unread_only)) parts.push('is:unread');
if (fromAddress) parts.push(`from:${fromAddress}`);
if (subject) parts.push(`subject:(${subject})`);

return [
  {
    json: {
      gmail_query: parts.join(' ').trim() || 'newer_than:7d',
      max_results: maxResults,
      unread_only: asBool(body.unread_only),
      source: asString(body.source) || 'n8n-email-search'
    }
  }
];

const response = $input.first().json;
const rawMessages = Array.isArray(response.messages) ? response.messages : [];

const messages = rawMessages.map((message) => ({
  message_id: message.id,
  thread_id: message.threadId,
  from: null,
  subject: null,
  date: null,
  snippet: null,
  unread: null
}));

return [
  {
    json: {
      messages,
      result_size_estimate: response.resultSizeEstimate ?? messages.length,
      note: messages.length
        ? 'Search returns Gmail message IDs. Call email_read with message_id for body, sender, subject, and snippet.'
        : 'No matching messages found.',
      source: 'n8n-email-search',
      send_email: false
    }
  }
];
